          </Typography>
          <Button onClick={handleClickHair}>
          {isCat ? "Change Fur Color" : "Change Hair Color"}
          </Button>
          {isDudeLela && (
          <>
            <Typography variant="h6" gutterBottom>
              Beard
            </Typography>
            <Button onClick={handleClickBeard}>Change Beard Color</Button>
          </>
        )}
          <Typography variant="h6" gutterBottom>
